INSERT INTO `bank_soals` VALUES (1,1,2,'pilihan_ganda','Apa tujuan utama Satu Data Indonesia?','[\"Menyatukan prinsip tata kelola data pemerintah\", \"Menghapus seluruh data OPD\", \"Mengganti seluruh aplikasi daerah\", \"Membatasi publikasi data\"]','Menyatukan prinsip tata kelola data pemerintah','Jawaban mengacu pada konsep dasar Satu Data Indonesia.',1.00,1,4,'2026-07-15 19:04:15','2026-07-20 17:28:27',NULL),(2,1,2,'pilihan_ganda','Siapa yang berperan mendukung pengelolaan data pada OPD?','[\"Walidata Pendukung\", \"Operator sekolah\", \"Bendahara\", \"Arsiparis umum\"]','Walidata Pendukung','Jawaban mengacu pada konsep dasar Satu Data Indonesia.',1.00,1,4,'2026-07-15 19:04:15','2026-07-20 17:28:27',NULL),(3,1,2,'pilihan_ganda','Salah satu prinsip Satu Data Indonesia adalah?','[\"Memenuhi standar data\", \"Data tidak perlu metadata\", \"Data hanya disimpan lokal\", \"Data tidak perlu dibagi-pakaikan\"]','Memenuhi standar data','Jawaban mengacu pada konsep dasar Satu Data Indonesia.',1.00,1,4,'2026-07-15 19:04:15','2026-07-20 17:28:27',NULL),(4,1,2,'pilihan_ganda','Metadata digunakan untuk?','[\"Menjelaskan definisi dan struktur data\", \"Menghapus data lama\", \"Mengubah password akun\", \"Membuat sertifikat otomatis\"]','Menjelaskan definisi dan struktur data','Jawaban mengacu pada konsep dasar Satu Data Indonesia.',1.00,1,4,'2026-07-15 19:04:15','2026-07-20 17:28:27',NULL),(5,1,2,'essay','Forum Satu Data Indonesia berfungsi sebagai?',NULL,'Wadah koordinasi penyelenggaraan data','Jawaban mengacu pada konsep dasar Satu Data Indonesia.',1.00,1,4,'2026-07-15 19:04:15','2026-07-21 17:06:14',NULL),(6,8,1,'essay','jnuw',NULL,'xwxw',NULL,1.00,1,1,'2026-07-17 21:47:56','2026-07-17 21:49:10','2026-07-17 21:49:10');
